Actionscript.script:
声音 = "";
霰弹值 = 1;
子弹散射度 = 0;
发射效果 = "";
子弹种类 = "火焰爆发";
if(子弹威力 == undefined)
{
   子弹威力 = 500;
}
子弹速度 = 10;
击中地图效果 = "";
Z轴攻击范围 = 120;
击倒率 = 0;
击中后子弹的效果 = "";
 击退初速度 = 20;
if(子弹敌我属性值 == undefined)
{
   子弹敌我属性值 = true;
}
shootX = this._x;
Z轴坐标 = shootY = this._y;
if(发射者名 == undefined)
{
   发射者名 = _root.控制目标;
}
子弹属性 = _root.子弹属性初始化(this,"火焰爆发",发射者名);
子弹属性.声音 = "";
子弹属性.霰弹值 = 1;
子弹属性.子弹散射度 = 0;
子弹属性.子弹种类 = "火焰爆发";
子弹属性.子弹威力 = 子弹威力;
子弹属性.子弹速度 = 0;
子弹属性.击中地图效果 = "";
子弹属性.Z轴攻击范围 = 120;
子弹属性.击倒率 = 10;
子弹属性.水平击退速度 = 15;
子弹属性.垂直击退速度 = 3;
子弹属性.击中后子弹的效果 = "";
子弹属性.子弹敌我属性 = 子弹敌我属性值;
子弹属性.伤害类型 = "物理";
子弹属性.shootX = this._x;
子弹属性.shootY = this._y;
子弹属性.shootZ = this._y;
子弹属性.发射者 = 发射者名;
_root.子弹区域shoot传递(子弹属性);
stop();
this.removeMovieClip();
